Here is the Code in c++ for task scheduling . Both the leetcode question and follow up question is solved. for leetcode question return vector size and for follow up question just print the question.
```
class Solution {
public:
    int leastInterval(vector<char> &v, int k) 
    {

        int n=v.size();
        int freq[26];
        memset(freq,0,sizeof(freq));
        for(int i=0;i<n;i++)
        {
            char ch=v[i];
            freq[ch-'A']++;
        }
        int lstindex[26];
        for(int i=0;i<26;i++)
        {
            lstindex[i]=-1000;
        }
        vector<string> ans;
        int index=0;
        while(1)
        {
            int mx=0;
            int ch=0;
            bool flag=true;
            for(int i=0;i<26;i++) //repi(0,25,1)
            {
                if(freq[i]>0)
                {
                    flag=false;
                }
                if((index-lstindex[i]-1)>=k)
                {
                    if(freq[i]>mx)
                    {
                        mx=freq[i];
                        ch=i;
                    }
                }
            }
            if(flag)
            {
                break;
            }
            if(mx==0)
            {
                ans.push_back("IDLE");
            }
            else
            {
                char c='A'+ch;
                string t="";
                t+=c;
                lstindex[ch]=index;
                freq[ch]--;
                ans.push_back(t);
            }
            index++;
        }
        return ans.size();
    }
};
```
